// ============================================================================
// Constants
// ============================================================================

var CABLE_TYPES = {"straight":8100,"cross":8101,"roll":8102,"fiber":8103,"phone":8104,"cable":8105,"serial":8106,"auto":8107,"console":8108,"wireless":8109,"coaxial":8110,"octal":8111,"cellular":8112,"usb":8113,"custom_io":8114};

var DEVICE_TYPES = {"router":0,"switch":1,"hub":2,"pc":3,"server":4,"printer":5,"wireless":6,"cloud":7,"end":8};

var MODEL_ALIASES = {"pc":"PC-PT","laptop":"Laptop-PT","server":"Server-PT","cloud":"Cloud-PT","ap":"AccessPoint-PT","accesspoint":"AccessPoint-PT"};

var CABLE_TYPE_NAMES = {"8100":"straight","8101":"cross","8102":"roll","8103":"fiber","8104":"phone","8105":"cable","8106":"serial","8107":"auto","8108":"console","8109":"wireless","8110":"coaxial","8111":"octal","8112":"cellular","8113":"usb","8114":"custom_io"};

// ============================================================================
// Helpers
// ============================================================================

function getLW() {
  return ipc.appWindow().getActiveWorkspace().getLogicalWorkspace();
}

function getNet() {
  return ipc.network();
}

function resolveModel(model) {
  if (!model) return "2911";
  var key = model.toLowerCase();
  return MODEL_ALIASES[key] || model;
}

function getDeviceTypeForModel(model) {
  var name = (model || "").toLowerCase();
  if (name.indexOf("2960") === 0 || name.indexOf("3560") === 0 || name.indexOf("switch") >= 0) return DEVICE_TYPES.switch;
  if (name.indexOf("pc") === 0 || name.indexOf("laptop") === 0) return DEVICE_TYPES.pc;
  if (name.indexOf("server") === 0) return DEVICE_TYPES.server;
  if (name.indexOf("accesspoint") >= 0 || name.indexOf("wireless") >= 0) return DEVICE_TYPES.wireless;
  if (name.indexOf("cloud") >= 0) return DEVICE_TYPES.cloud;
  return DEVICE_TYPES.router;
}

function getDeviceTypeCandidates(model) {
  var normalized = (model || "").toLowerCase();
  
  if (normalized.indexOf("2960") === 0 || normalized.indexOf("3560") === 0 || normalized.indexOf("switch") >= 0) {
    return [DEVICE_TYPES.switch, DEVICE_TYPES.router];
  }
  
  if (normalized.indexOf("pc") === 0 || normalized.indexOf("laptop") === 0) {
    var candidates = [DEVICE_TYPES.pc, DEVICE_TYPES.end];
    for (var t = 8; t <= 60; t++) {
      if (candidates.indexOf(t) === -1) candidates.push(t);
    }
    return candidates;
  }
  
  if (normalized.indexOf("server") === 0) {
    var serverCandidates = [DEVICE_TYPES.server, DEVICE_TYPES.end];
    for (var s = 8; s <= 60; s++) {
      if (serverCandidates.indexOf(s) === -1) serverCandidates.push(s);
    }
    return serverCandidates;
  }
  
  return [DEVICE_TYPES.router, DEVICE_TYPES.switch, DEVICE_TYPES.pc];
}

function createDeviceWithFallback(model, x, y, typeList, lw, net) {
  for (var i = 0; i < typeList.length; i++) {
    var typeId = typeList[i];
    var autoName = lw.addDevice(typeId, model, x, y);
    if (!autoName) continue;
    
    var device = net.getDevice(autoName);
    if (!device) {
      lw.removeDevice(autoName);
      continue;
    }
    
    var deviceModel = "";
    try { deviceModel = (device.getModel && device.getModel()) || ""; } catch (e) {}
    
    if (deviceModel && deviceModel.toLowerCase() === model.toLowerCase()) {
      return { autoName: autoName, device: device, typeId: typeId };
    }
    
    lw.removeDevice(autoName);
  }
  return null;
}

// ============================================================================
// IOS Output Parsers
// ============================================================================

var IOS_PARSERS = {
  "show ip interface brief": function(output) {
    var interfaces = [];
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)$/);
      if (match && match[1] !== "Interface") {
        interfaces.push({
          interface: match[1],
          ipAddress: match[2],
          ok: match[3],
          method: match[4],
          status: match[5],
          protocol: match[6]
        });
      }
    }
    return { raw: output, interfaces: interfaces };
  },

  "show vlan brief": function(output) {
    var vlans = [];
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(\d+)\s+(\S+)\s+(\S+)\s*(.*?)$/);
      if (match) {
        var ports = match[4] ? match[4].split(",").map(function(p) { return p.trim(); }).filter(function(p) { return p; }) : [];
        vlans.push({ id: parseInt(match[1]), name: match[2], status: match[3], ports: ports });
      }
    }
    return { raw: output, vlans: vlans };
  },

  "show vlan": function(output) {
    return IOS_PARSERS["show vlan brief"](output);
  },

  "show ip route": function(output) {
    var routes = [];
    var gatewayOfLastResort = null;
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var gwMatch = line.match(/Gateway of last resort is (.+)/i);
      if (gwMatch) {
        gatewayOfLastResort = gwMatch[1];
        continue;
      }
      var routeMatch = line.match(/^([CLSORDBEIUM*])\s+(\S+)\s+(?:is\s+)?(.+)$/);
      if (routeMatch) {
        var route = { type: routeMatch[1], network: routeMatch[2], nextHop: null, interface: null };
        var rest = routeMatch[3];
        if (rest.indexOf("directly connected") >= 0) {
          var ifaceMatch = rest.match(/connected,\s*(\S+)/);
          if (ifaceMatch) route.interface = ifaceMatch[1];
        } else if (rest.indexOf("via") >= 0) {
          var viaMatch = rest.match(/via\s+(\S+)/);
          if (viaMatch) route.nextHop = viaMatch[1].replace(",", "");
        }
        routes.push(route);
      }
    }
    return { raw: output, routes: routes, gatewayOfLastResort: gatewayOfLastResort };
  },

  "show running-config": function(output) {
    var sections = {};
    var interfaces = {};
    var currentSection = null;
    var currentContent = [];
    var hostname = null;
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      if (line.startsWith("hostname ")) hostname = line.substring(9).trim();
      if (line === "!") {
        if (currentSection) sections[currentSection] = currentContent.join("\n");
        currentSection = null;
        currentContent = [];
      } else if (line.startsWith("interface ")) {
        currentSection = line.trim();
        currentContent.push(line);
        interfaces[line.substring(10).trim()] = "";
      } else if (line.startsWith("vlan ") || line.startsWith("router ")) {
        currentSection = line.trim();
        currentContent.push(line);
      } else if (currentSection) {
        currentContent.push(line);
      }
    }
    return { raw: output, hostname: hostname, sections: sections, interfaces: interfaces };
  },

  "show interfaces": function(output) {
    var interfaces = [];
    var current = null;
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      var ifaceMatch = line.match(/^(\S+)\s+is\s+(\S+),\s+line protocol is (\S+)/);
      if (ifaceMatch) {
        if (current) interfaces.push(current);
        current = { name: ifaceMatch[1], status: ifaceMatch[2], protocol: ifaceMatch[3] };
      }
      if (current) {
        if (line.startsWith("  Hardware is ")) current.hardware = line.substring(14).trim();
        if (line.startsWith("  Description: ")) current.description = line.substring(15).trim();
        if (line.startsWith("  Internet address is ")) {
          var ipMatch = line.match(/Internet address is (\S+)/);
          if (ipMatch) {
            var parts = ipMatch[1].split("/");
            current.ipAddress = parts[0];
            if (parts[1]) current.cidr = parseInt(parts[1]);
          }
        }
      }
    }
    if (current) interfaces.push(current);
    return { raw: output, interfaces: interfaces };
  },

  "show ip arp": function(output) {
    var entries = [];
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(Internet)\s+(\S+)\s+(\S+)\s+([0-9a-fA-F.]+)\s+(\S+)\s+(\S+)$/i);
      if (match) {
        entries.push({ protocol: match[1], address: match[2], age: match[3], mac: match[4], type: match[5], interface: match[6] });
      }
    }
    return { raw: output, entries: entries };
  },

  "show mac address-table": function(output) {
    var entries = [];
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      var match = line.match(/^(\S+)\s+([0-9a-fA-F.]+)\s+(\S+)\s+(\S+)$/);
      if (match) {
        entries.push({ vlan: match[1], macAddress: match[2], type: match[3].toLowerCase(), ports: [match[4]] });
      }
    }
    return { raw: output, entries: entries };
  },

  "show spanning-tree": function(output) {
    var vlans = [];
    var current = null;
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      var vlanMatch = line.match(/^VLAN(\d+)/);
      if (vlanMatch) {
        if (current) vlans.push(current);
        current = { vlan: parseInt(vlanMatch[1]), interfaces: [] };
      }
      if (current) {
        if (line.startsWith("  Root ID")) current.rootBridgeId = line.substring(10).trim();
        if (line.startsWith("  Bridge ID")) current.bridgeId = line.substring(12).trim();
        var ifaceMatch = line.match(/^\s+(\S+)\s+(\S+)\s+(\S+)\s+(\d+)\s+(\S+)/);
        if (ifaceMatch) {
          current.interfaces.push({ port: ifaceMatch[1], role: ifaceMatch[2].toLowerCase(), state: ifaceMatch[3].toLowerCase(), cost: parseInt(ifaceMatch[4]) });
        }
      }
    }
    if (current) vlans.push(current);
    return { raw: output, vlans: vlans };
  },

  "show version": function(output) {
    var result = { raw: output };
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i];
      if (line.includes("Version ")) {
        var vMatch = line.match(/Version (\S+)/);
        if (vMatch) result.version = vMatch[1];
      }
      if (line.includes(" uptime is ")) result.uptime = line.substring(line.indexOf(" uptime is ") + 11);
      var uptimeMatch = line.match(/^(\S+)\s+uptime is /);
      if (uptimeMatch) result.hostname = uptimeMatch[1];
    }
    return result;
  },

  "show cdp neighbors": function(output) {
    var neighbors = [];
    var started = false;
    var lines = output.split("\n");
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      if (line.includes("Device ID")) { started = true; continue; }
      if (!started || !line) continue;
      var parts = line.split(/\s+/);
      if (parts.length >= 6) {
        neighbors.push({ deviceId: parts[0], localInterface: parts[1], holdtime: parseInt(parts[2]), capability: parts[3], platform: parts[4], portId: parts[5] });
      }
    }
    return { raw: output, neighbors: neighbors };
  }
};

function __getParser(command) {
  var cmd = command.toLowerCase().trim();
  if (IOS_PARSERS[cmd]) return IOS_PARSERS[cmd];
  for (var key in IOS_PARSERS) {
    if (cmd.startsWith(key.toLowerCase())) return IOS_PARSERS[key];
  }
  return null;
}

// ============================================================================
// IOS Session State Management (with filesystem persistence)
// Tracks mode, paging, and confirmation state per device across commands
// Includes automatic cleanup to prevent memory leaks
// Sessions persist across PT hot-reloads via filesystem
// ============================================================================

var IOS_SESSIONS = {};
var SESSION_MAX_AGE_MS = 300000; // 5 minutes
var MAX_SESSIONS = 200; // Increased from 50 to support larger labs
var SESSIONS_FILE = DEV_DIR + "/sessions/ios-sessions.json";

function loadSessionsFromDisk() {
  try {
    if (fm.fileExists(SESSIONS_FILE)) {
      var content = fm.getFileContents(SESSIONS_FILE);
      var loaded = JSON.parse(content);
      var now = Date.now();
      var loadedCount = 0;

      for (var key in loaded) {
        if (loaded[key] && loaded[key].lastUsed && (now - loaded[key].lastUsed < SESSION_MAX_AGE_MS)) {
          IOS_SESSIONS[key] = loaded[key];
          loadedCount++;
        }
      }

      dprint("[Sessions] Loaded " + loadedCount + " sessions from disk");
    }
  } catch (e) {
    dprint("[Sessions] Failed to load from disk: " + e);
  }
}

function saveSessionsToDisk() {
  try {
    var tempFile = SESSIONS_FILE + ".tmp";
    fm.writeFile(tempFile, JSON.stringify(IOS_SESSIONS, null, 2));
    fm.renameFile(tempFile, SESSIONS_FILE);
  } catch (e) {
    dprint("[Sessions] Failed to save to disk: " + e);
  }
}

function cleanupStaleSessions() {
  var now = Date.now();
  var keys = Object.keys(IOS_SESSIONS);
  var activeKeys = [];

  // Evict by age first
  for (var i = 0; i < keys.length; i++) {
    var key = keys[i];
    var session = IOS_SESSIONS[key];
    if (session && session.lastUsed) {
      var age = now - session.lastUsed;
      if (age > SESSION_MAX_AGE_MS) {
        delete IOS_SESSIONS[key];
      } else {
        activeKeys.push(key);
      }
    } else {
      delete IOS_SESSIONS[key];
    }
  }

  // Evict excess by LRU (keep most recently used)
  if (activeKeys.length > MAX_SESSIONS) {
    activeKeys.sort(function(a, b) {
      var aTime = IOS_SESSIONS[a] && IOS_SESSIONS[a].lastUsed || 0;
      var bTime = IOS_SESSIONS[b] && IOS_SESSIONS[b].lastUsed || 0;
      return aTime - bTime;
    });

    var toRemove = activeKeys.length - MAX_SESSIONS;
    for (var j = 0; j < toRemove; j++) {
      dprint("[Sessions] Evicting session for " + activeKeys[j] + " (LRU)");
      delete IOS_SESSIONS[activeKeys[j]];
    }
  }

  saveSessionsToDisk();
}

function getOrCreateSession(deviceName, term) {
  // Load from disk on first access if not yet loaded
  if (Object.keys(IOS_SESSIONS).length === 0) {
    loadSessionsFromDisk();
  }

  cleanupStaleSessions();

  if (!IOS_SESSIONS[deviceName]) {
    IOS_SESSIONS[deviceName] = {
      mode: "user-exec",
      paging: false,
      awaitingConfirm: false,
      deviceName: deviceName,
      lastUsed: Date.now(),
      createdAt: Date.now()
    };
    saveSessionsToDisk();
  }

  IOS_SESSIONS[deviceName].lastUsed = Date.now();
  return IOS_SESSIONS[deviceName];
}

function inferPromptMode(output) {
  var lastLine = "";
  var lines = output.split("\n");
  for (var i = lines.length - 1; i >= 0; i--) {
    var line = lines[i].trim();
    if (line) {
      lastLine = line;
      break;
    }
  }

  if (/--More--/i.test(lastLine) || /\x1B\?D/.test(lastLine)) {
    return "paging";
  }
  if (/^\[confirm\]/i.test(lastLine)) {
    return "awaiting-confirm";
  }
  if (/^Password:/i.test(lastLine)) {
    return "awaiting-password";
  }

  var promptMatchers = [
    { pattern: /\(config-router\)#$/, mode: "config-router" },
    { pattern: /\(config-line\)#$/, mode: "config-line" },
    { pattern: /\(config-if\)#$/, mode: "config-if" },
    { pattern: /\(config\)#$/, mode: "config" },
    { pattern: /#$/, mode: "priv-exec" },
    { pattern: />$/, mode: "user-exec" },
  ];

  for (var i = 0; i < promptMatchers.length; i++) {
    if (promptMatchers[i].pattern.test(lastLine)) {
      return promptMatchers[i].mode;
    }
  }

  return "unknown";
}

function isPrivilegedMode(mode) {
  return mode === "priv-exec" || mode === "config" ||
         mode === "config-if" || mode === "config-line" || mode === "config-router";
}

function isConfigMode(mode) {
  return mode && mode.indexOf("config") === 0;
}

function updateSessionFromOutput(session, output, term) {
  var mode = inferPromptMode(output);

  if (mode === "paging") {
    session.paging = true;
    return;
  }
  session.paging = false;

  if (mode === "awaiting-confirm") {
    session.awaitingConfirm = true;
    return;
  }
  session.awaitingConfirm = false;

  if (mode === "awaiting-password") {
    return;
  }

  if (mode !== "unknown") {
    session.mode = mode;
  }
}

function executeIosCommand(term, cmd, session) {
  var response = term.enterCommand(cmd);
  if (!response || !response[0]) {
    updateSessionFromOutput(session, response[1] || "", term);
    return response || [0, ""];
  }

  var status = response[0];
  var output = response[1] || "";

  updateSessionFromOutput(session, output, term);

  while (session.paging) {
    var pageResponse = term.enterCommand(" ");
    updateSessionFromOutput(session, pageResponse[1] || "", term);
    output += pageResponse[1] || "";
  }

  if (session.awaitingConfirm) {
    var confirmResponse = term.enterCommand("\n");
    updateSessionFromOutput(session, confirmResponse[1] || "", term);
    output += confirmResponse[1] || "";
  }

  return [status, output];
}

function ensurePrivileged(term, session) {
  if (isPrivilegedMode(session.mode)) {
    return [true, ""];
  }

  var result = executeIosCommand(term, "enable", session);
  return [result[0] === 0, result[1]];
}

function ensureConfigMode(term, session) {
  if (isConfigMode(session.mode)) {
    return [true, ""];
  }

  if (!isPrivilegedMode(session.mode)) {
    var privResult = ensurePrivileged(term, session);
    if (!privResult[0]) {
      return [false, privResult[1]];
    }
  }

  var result = executeIosCommand(term, "configure terminal", session);
  return [result[0] === 0, result[1]];
}

// ============================================================================
// Command Handlers
// ============================================================================

function handleAddDevice(payload) {
  var lw = getLW();
  var net = getNet();
  var model = resolveModel(payload.model);
  var name = payload.name || model;
  var x = payload.x !== undefined ? payload.x : 100;
  var y = payload.y !== undefined ? payload.y : 100;
  
  var typeList = payload.deviceType !== undefined 
    ? [payload.deviceType] 
    : getDeviceTypeCandidates(model);
  
  var created = createDeviceWithFallback(model, x, y, typeList, lw, net);
  if (!created) {
    return { ok: false, error: "Failed to add device for model: " + model };
  }
  
  var autoName = created.autoName;
  var device = created.device;
  
  device.setName(name);
  if (device.skipBoot) device.skipBoot();
  
  return { ok: true, name: name, autoName: autoName, model: model, deviceType: created.typeId };
}

function handleRemoveDevice(payload) {
  getLW().removeDevice(payload.name);
  return { ok: true, name: payload.name };
}

function handleListDevices() {
  var net = getNet();
  var count = net.getDeviceCount();
  var devices = [];
  
  for (var i = 0; i < count; i++) {
    var device = net.getDeviceAt(i);
    if (device) {
      devices.push({
        name: device.getName(),
        model: device.getModel(),
        type: device.getType(),
        power: device.getPower()
      });
    }
  }
  
  return { ok: true, devices: devices, count: count };
}

function handleRenameDevice(payload) {
  var device = getNet().getDevice(payload.oldName);
  if (!device) return { ok: false, error: "Device not found: " + payload.oldName };
  device.setName(payload.newName);
  return { ok: true, oldName: payload.oldName, newName: payload.newName };
}

function handleAddModule(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  if (!device.addModule) return { ok: false, error: "Device does not support modular expansion" };
  
  var wasPowered = device.getPower();
  
  if (wasPowered) device.setPower(false);
  
  var result = device.addModule(payload.slot, payload.module);
  
  if (wasPowered) {
    device.setPower(true);
    if (device.skipBoot) device.skipBoot();
  }
  
  if (!result) return { ok: false, error: "Failed to add module to slot " + payload.slot };
  
  return { ok: true, device: payload.device, slot: payload.slot, module: payload.module };
}

function handleRemoveModule(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  if (!device.removeModule) return { ok: false, error: "Device does not support modular expansion" };
  
  var wasPowered = device.getPower();
  
  if (wasPowered) device.setPower(false);
  
  var result = device.removeModule(payload.slot);
  
  if (wasPowered) {
    device.setPower(true);
    if (device.skipBoot) device.skipBoot();
  }
  
  if (!result) return { ok: false, error: "Failed to remove module from slot " + payload.slot };
  
  return { ok: true, device: payload.device, slot: payload.slot };
}

function handleAddLink(payload) {
  var lw = getLW();
  var cableType = CABLE_TYPES[payload.linkType] || CABLE_TYPES.auto;
  
  var success = lw.createLink(
    payload.device1, payload.port1,
    payload.device2, payload.port2,
    cableType
  );
  
  if (!success) return { ok: false, error: "Failed to create link" };
  
  return {
    ok: true,
    device1: payload.device1,
    port1: payload.port1,
    device2: payload.device2,
    port2: payload.port2,
    linkType: payload.linkType || "auto"
  };
}

function handleRemoveLink(payload) {
  getLW().deleteLink(payload.device, payload.port);
  return { ok: true };
}

function handleConfigHost(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  var port = device.getPortAt(0);
  if (!port) return { ok: false, error: "No ports on device" };
  
  if (payload.dhcp === true) {
    try { port.setDhcpEnabled(true); } catch(e) {}
  } else {
    if (payload.ip && payload.mask) {
      port.setIpSubnetMask(payload.ip, payload.mask);
    }
    if (payload.gateway) {
      port.setDefaultGateway(payload.gateway);
    }
    if (payload.dns) {
      port.setDnsServerIp(payload.dns);
    }
  }
  
  return { ok: true, device: payload.device, ip: payload.ip };
}

function classifyIosOutput(output) {
  var trimmed = (output || "").trim();

  // Error patterns
  if (trimmed.indexOf("% Invalid input") >= 0) {
    return { category: "invalid", ok: false };
  }
  if (trimmed.indexOf("% Incomplete command") >= 0) {
    return { category: "incomplete", ok: false };
  }
  if (trimmed.indexOf("% Ambiguous command") >= 0) {
    return { category: "ambiguous", ok: false };
  }
  if (trimmed.indexOf("% ") >= 0 && trimmed.indexOf("ERROR") >= 0) {
    return { category: "error", ok: false };
  }

  // Success patterns
  if (trimmed.indexOf("--More--") >= 0) {
    return { category: "paging", ok: true };
  }
  if (trimmed.indexOf("[confirm]") >= 0) {
    return { category: "confirm", ok: true };
  }

  // Default
  return { category: "success", ok: true };
}

function handleConfigIos(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };

  if (device.skipBoot) device.skipBoot();

  var term = device.getCommandLine();
  if (!term) return { ok: false, error: "Device does not support CLI" };

  var session = getOrCreateSession(payload.device, term);

  var configResult = ensureConfigMode(term, session);
  if (!configResult[0]) {
    dprint("[handleConfigIos] Failed to enter config mode: " + configResult[1]);
    return { ok: false, error: "Failed to enter config mode: " + configResult[1], phase: "pre-exec" };
  }

  var results = [];
  var failedCount = 0;
  var stopOnError = payload.stopOnError !== false; // Default: fail-fast

  for (var i = 0; i < payload.commands.length; i++) {
    var cmd = payload.commands[i];
    var cmdResult = executeIosCommand(term, cmd, session);
    var status = cmdResult[0];
    var output = cmdResult[1];

    var classification = classifyIosOutput(output);
    var cmdOk = status === 0 && classification.ok;

    results.push({
      index: i,
      command: cmd,
      ok: cmdOk,
      status: status,
      output: output.slice(0, 500),
      classification: classification.category
    });

    if (!cmdOk) {
      failedCount++;
      if (stopOnError) {
        return {
          ok: false,
          error: "Command failed (abort on error): " + cmd,
          failedAt: i,
          totalCommands: payload.commands.length,
          executedCount: i + 1,
          failedCount: failedCount,
          results: results,
          session: { mode: session.mode }
        };
      }
    }
  }

  if (payload.save !== false) {
    executeIosCommand(term, "write memory", session);
  }

  return {
    ok: failedCount === 0,
    device: payload.device,
    totalCommands: payload.commands.length,
    executedCount: results.length,
    failedCount: failedCount,
    results: results,
    session: { mode: session.mode }
  };
}

function handleExecIos(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };

  var cmd = (payload.command || "").toLowerCase().trim();

  if (cmd === "show running-config" || cmd === "show startup-config") {
    return handleShowConfig(device, payload);
  }

  if (cmd === "show version") {
    return handleShowVersion(device, payload);
  }

  if (cmd.startsWith("show ip ")) {
    return handleShowIpCommand(device, payload);
  }

  var term = device.getCommandLine();
  if (!term) {
    return { ok: false, error: "Device does not support CLI" };
  }

  var session = getOrCreateSession(payload.device, term);

  try {
    var cmdResult = executeIosCommand(term, payload.command, session);
    var status = cmdResult[0];
    var output = cmdResult[1];

    dprint("[execIos] session.execute: status=" + status + ", output length=" + output.length + ", mode=" + session.mode);

    var classification = classifyIosOutput(output);

    var result = {
      ok: status === 0 && classification.ok,
      raw: output,
      status: status,
      classification: classification.category,
      session: { mode: session.mode, paging: session.paging, awaitingConfirm: session.awaitingConfirm }
    };

    if (!result.ok && classification.category !== "success") {
      result.error = {
        code: classification.category.toUpperCase(),
        message: "IOS returned error: " + classification.category,
        raw: output.slice(0, 200)
      };
    }

    if (payload.parse !== false) {
      var parser = getParser(payload.command);
      if (parser) {
        try {
          result.parsed = parser(output);
        } catch (e) {
          result.parseError = String(e);
        }
      }
    }

    return result;
  } catch (e) {
    dprint("[execIos] executeIosCommand error: " + String(e));
    return { ok: false, error: "Failed to execute command: " + String(e), raw: "" };
  }
}

function generateSimulatedConfig(device) {
  var name = device.getName();
  var model = device.getModel();
  var power = device.getPower();
  var type = device.getType();
  var portCount = device.getPortCount();
  var ports = [];

  for (var i = 0; i < portCount; i++) {
    try {
      var port = device.getPortAt(i);
      if (port) {
        var portName = port.getName();
        var ip = port.getIpAddress();
        var mask = port.getSubnetMask();
        if (ip && ip !== "0.0.0.0") {
          ports.push("interface " + portName + "\n ip address " + ip + " " + mask);
        }
      }
    } catch(e) {}
  }

  var config = "!\n! WARNING: Simulated config (PT CLI unavailable)\n!\nversion 15.2\nhostname " + name + "\n!\n";
  if (ports.length > 0) {
    config += ports.join("\n!\n") + "\n";
  }
  if (!power) {
    config += "!\n% Device is powered off\n";
  }

  return {
    ok: true,
    raw: config,
    status: 0,
    simulated: true,
    parsed: {
      raw: config,
      hostname: name,
      version: "15.2",
      sections: [],
      interfaces: {}
    }
  };
}

function handleShowConfig(device, payload) {
  var term = device.getCommandLine();
  if (!term) {
    dprint("[handleShowConfig] No CLI terminal, using simulated config");
    return generateSimulatedConfig(device);
  }

  var session = getOrCreateSession(device.getName(), term);

  try {
    // Execute real command
    var cmdResult = executeIosCommand(term, "show running-config", session);
    var status = cmdResult[0];
    var output = cmdResult[1];

    if (status !== 0) {
      dprint("[handleShowConfig] Command failed (status=" + status + "), using simulated");
      return generateSimulatedConfig(device);
    }

    var result = {
      ok: true,
      raw: output,
      status: status,
      simulated: false,
      session: { mode: session.mode }
    };

    // Parse if requested
    if (payload.parse !== false) {
      var parser = getParser("show running-config");
      if (parser) {
        try {
          result.parsed = parser(output);
        } catch (e) {
          result.parseError = String(e);
        }
      }
    }

    dprint("[handleShowConfig] Real config returned: " + output.length + " chars");
    return result;

  } catch (e) {
    dprint("[handleShowConfig] Error executing command: " + e + ", using simulated");
    return generateSimulatedConfig(device);
  }
}

