function handleShowIpCommand(device, payload) {
  var cmd = (payload.command || "").toLowerCase();

  if (cmd === "show ip interface brief" || cmd === "show ip int brief") {
    var portCount = 0;
    try { portCount = device.getPortCount(); } catch(e) {}
    var interfaces = [];

    interfaces.push({interface: "Vlan1", ipAddress: "unassigned", ok: "NVRAM", method: "manual", status: "down", protocol: "down"});

    for (var i = 0; i < portCount; i++) {
      try {
        var port = device.getPortAt(i);
        if (port) {
          var portName = "";
          var ip = "unassigned";
          try { portName = port.getName(); } catch(e1) {}
          try { ip = port.getIpAddress(); } catch(e1) {}
          var status = (ip && ip !== "0.0.0.0" && ip !== "unassigned") ? "up" : "down";
          interfaces.push({
            interface: portName,
            ipAddress: ip === "0.0.0.0" ? "unassigned" : ip,
            ok: "NVRAM",
            method: "manual",
            status: status,
            protocol: status === "up" ? "up" : "down"
          });
        }
      } catch(e) {}
    }

    var header = "Interface              IP-Address      OK? Method Status                Protocol";
    var lines = [];
    for (var j = 0; j < interfaces.length; j++) {
      var iface = interfaces[j];
      var line = iface.interface.padEnd(20) + iface.ipAddress.padEnd(16) + "YES   " + iface.method.padEnd(8) + iface.status.padEnd(20) + iface.protocol;
      lines.push(line);
    }
    var output = [header].concat(lines).join("\n");

    dprint("[execIos] Generated IP interface brief: " + output.length + " chars");

    var parsedIfaces = [];
    for (var k = 0; k < interfaces.length; k++) {
      var iface2 = interfaces[k];
      parsedIfaces.push({
        interface: iface2.interface,
        ipAddress: iface2.ipAddress === "unassigned" ? "" : iface2.ipAddress,
        ok: iface2.ok,
        method: iface2.method,
        status: iface2.status,
        protocol: iface2.protocol
      });
    }

    return {
      ok: true,
      raw: output,
      status: 0,
      parsed: {
        raw: output,
        interfaces: parsedIfaces
      }
    };
  }

  if (cmd === "show ip route") {
    var output = "Codes: L - local, C - connected, S - static, R - RIP, M - mobile, B - BGP\n" +
      "     D - EIGRP, EX - EIGRP external, O - OSPF, IA - OSPF inter area\n" +
      "     N1 - OSPF NSSA external type 1, N2 - OSPF NSSA external type 2\n" +
      "     E1 - OSPF external type 1, E2 - OSPF external type 2, E - EGP\n" +
      "     i - IS-IS, L1 - IS-IS level-1, L2 - IS-IS level-2, ia - IS-IS inter area\n" +
      "     * - candidate default, U - per-user static route, o - ODR\n" +
      "     P - periodic downloaded static route\n\n" +
      "Gateway of last resort is not set";

    return {
      ok: true,
      raw: output,
      status: 0,
      parsed: {
        raw: output,
        routes: [],
        gatewayOfLastResort: "not set"
      }
    };
  }

  return { ok: false, error: "Unsupported show ip command: " + payload.command, raw: "" };
}

function handleSnapshot() {
  var net = getNet();
  var count = net.getDeviceCount();
  var devices = {};
  var linksMap = {}; // Use link UUID for O(1) deduplication

  for (var i = 0; i < count; i++) {
    var device = net.getDeviceAt(i);
    if (!device) continue;

    var name = device.getName();
    var portCount = device.getPortCount();
    var ports = [];

    for (var p = 0; p < portCount; p++) {
      try {
        var port = device.getPortAt(p);
        if (!port) continue;

        var portInfo = { name: port.getName(), type: "unknown" };

        try { portInfo.ipAddress = port.getIpAddress(); } catch(e) {}
        try { portInfo.subnetMask = port.getSubnetMask(); } catch(e) {}
        try { portInfo.macAddress = port.getMacAddress(); } catch(e) {}

        ports.push(portInfo);

        // O(n) link processing using UUID instead of O(n\u00B2) nested loops
        var link = port.getLink();
        if (link) {
          var linkId = link.getObjectUUID();

          // Only process if not already seen (O(1) lookup)
          if (!linksMap[linkId]) {
            var srcPort = link.getSourcePort();
            var dstPort = link.getDestPort();
            var srcDevice = srcPort.getDevice();
            var dstDevice = dstPort.getDevice();

            var dev1, pt1, dev2, pt2;
            if (srcDevice.getName() < dstDevice.getName()) {
              dev1 = srcDevice.getName(); pt1 = srcPort.getName();
              dev2 = dstDevice.getName(); pt2 = dstPort.getName();
            } else {
              dev1 = dstDevice.getName(); pt1 = dstPort.getName();
              dev2 = srcDevice.getName(); pt2 = srcPort.getName();
            }

            linksMap[linkId] = {
              id: linkId,
              device1: dev1,
              port1: pt1,
              device2: dev2,
              port2: pt2,
              type: CABLE_TYPE_NAMES[link.getLinkType()] || "auto",
              status: link.getStatus()
            };
          }
        }
      } catch(e) {
        ports.push({ name: "port" + p });
      }
    }

    devices[name] = {
      name: name,
      model: device.getModel(),
      type: device.getType(),
      power: device.getPower(),
      ports: ports
    };
  }

  // Convert linksMap to array
  var links = [];
  for (var linkId in linksMap) {
    links.push(linksMap[linkId]);
  }

  return {
    ok: true,
    version: "1.0",
    timestamp: Date.now(),
    devices: devices,
    links: links,
    metadata: { deviceCount: count, linkCount: Object.keys(links).length }
  };
}

function handleInspect(payload) {
  var device = getNet().getDevice(payload.device);
  if (!device) return { ok: false, error: "Device not found: " + payload.device };
  
  var portCount = device.getPortCount();
  var ports = [];
  
  for (var i = 0; i < portCount; i++) {
    try {
      var port = device.getPortAt(i);
      if (!port) continue;
      
      var portInfo = { name: port.getName() };
      try { portInfo.ipAddress = port.getIpAddress(); } catch(e) {}
      try { portInfo.subnetMask = port.getSubnetMask(); } catch(e) {}
      try { portInfo.macAddress = port.getMacAddress(); } catch(e) {}
      try { portInfo.defaultGateway = port.getDefaultGateway(); } catch(e) {}
      
      ports.push(portInfo);
    } catch(e) {}
  }
  
  var result = {
    ok: true,
    name: device.getName(),
    model: device.getModel(),
    type: device.getType(),
    power: device.getPower(),
    ports: ports
  };
  
  if (payload.includeXml && device.serializeToXml) {
    try { result.xml = device.serializeToXml(); } catch(e) {}
  }
  
  return result;
}

function handleHardwareInfo() {
  var factory = ipc.hardwareFactory();
  var keys = [];
  for (var key in factory) keys.push(key);
  return { ok: true, keys: keys };
}

function handleHardwareCatalog(payload) {
  var factory = ipc.hardwareFactory();
  var list = factory.devices || [];
  var limit = payload.limit || 50;
  var results = [];
  
  for (var i = 0; i < list.length && results.length < limit; i++) {
    var item = list[i];
    var entry = {};
    try { entry.name = item.name; } catch(e) {}
    try { entry.model = item.model; } catch(e) {}
    try { entry.displayName = item.displayName; } catch(e) {}
    try { entry.deviceType = item.deviceType; } catch(e) {}
    results.push(entry);
  }
  
  return { ok: true, items: results, total: list.length || 0 };
}

function handleCommandLog(payload) {
  var cl = ipc.commandLog();
  cl.setEnabled(true);
  
  var count = cl.getEntryCount();
  var limit = payload.limit || 100;
  var start = Math.max(0, count - limit);
  var entries = [];
  
  for (var i = start; i < count; i++) {
    var entry = cl.getEntryAt(i);
    entries.push({
      index: i,
      time: entry.getTimeToString ? entry.getTimeToString() : "",
      device: entry.getDeviceName ? entry.getDeviceName() : "",
      prompt: entry.getPrompt ? entry.getPrompt() : "",
      command: entry.getCommand ? entry.getCommand() : ""
    });
  }
  
  return { ok: true, entries: entries, count: count };
}

// ============================================================================
// Canvas/Rect Handlers
// ============================================================================

function handleListCanvasRects(payload) {
  var lw = getLW();
  var rectIds = [];

  try {
    if (lw.getCanvasRectIds) {
      rectIds = lw.getCanvasRectIds() || [];
    }
  } catch (e) {
    return { ok: false, error: "Failed to get canvas rect IDs: " + String(e) };
  }

  return { ok: true, rects: rectIds, count: rectIds.length };
}

function handleGetRect(payload) {
  var lw = getLW();
  var rectData = null;

  try {
    if (lw.getRectItemData) {
      rectData = lw.getRectItemData(payload.rectId) || null;
    } else if (lw.getRectData) {
      rectData = lw.getRectData(payload.rectId) || null;
    }
  } catch (e) {
    return { ok: false, error: "Failed to get rect data: " + String(e) };
  }

  if (!rectData) {
    return { ok: false, error: "Rect not found: " + payload.rectId };
  }

  return { ok: true, rectId: payload.rectId, data: rectData };
}

function handleDevicesInRect(payload) {
  var lw = getLW();
  var net = getNet();
  var devices = [];
  var clusters = [];

  try {
    if (lw.devicesAt) {
      var rectData = payload.rectId && lw.getRectItemData ? lw.getRectItemData(payload.rectId) : null;

      var x = 0, y = 0, width = 0, height = 0;

      if (rectData && typeof rectData === "object") {
        x = rectData.x || 0;
        y = rectData.y || 0;
        width = rectData.width || 0;
        height = rectData.height || 0;
      }

      if (width > 0 && height > 0) {
        var foundDevices = lw.devicesAt(x, y, width, height, payload.includeClusters || false);
        if (Array.isArray(foundDevices)) {
          for (var i = 0; i < foundDevices.length; i++) {
            if (typeof foundDevices[i] === "string") {
              devices.push(foundDevices[i]);
            }
          }
        }
      }
    }

    if (devices.length === 0 && payload.rectId) {
      var rectData = lw.getRectItemData ? lw.getRectItemData(payload.rectId) : null;

      if (rectData && typeof rectData === "object") {
        var rx = rectData.x || 0;
        var ry = rectData.y || 0;
        var rw = rectData.width || 0;
        var rh = rectData.height || 0;

        var deviceCount = net.getDeviceCount();
        for (var i = 0; i < deviceCount; i++) {
          var device = net.getDeviceAt(i);
          if (!device) continue;

          var deviceX = device.getX ? device.getX() : 0;
          var deviceY = device.getY ? device.getY() : 0;

          if (deviceX >= rx && deviceX <= rx + rw && deviceY >= ry && deviceY <= ry + rh) {
            devices.push(device.getName());
          }
        }
      }
    }
  } catch (e) {
    return { ok: false, error: "Failed to get devices in rect: " + String(e) };
  }

  return { ok: true, rectId: payload.rectId, devices: devices, clusters: clusters, count: devices.length };
}

// ============================================================================
// Command Dispatcher
// ============================================================================

return (function(payload, ipc, dprint) {
  try {
    dprint("[Runtime] Processing: " + payload.type);
    
    switch (payload.type) {
      case "addDevice": return handleAddDevice(payload);
      case "removeDevice": return handleRemoveDevice(payload);
      case "listDevices": return handleListDevices(payload);
      case "renameDevice": return handleRenameDevice(payload);
      case "addModule": return handleAddModule(payload);
      case "removeModule": return handleRemoveModule(payload);
      case "addLink": return handleAddLink(payload);
      case "removeLink": return handleRemoveLink(payload);
      case "configHost": return handleConfigHost(payload);
      case "configIos": return handleConfigIos(payload);
      case "execIos": return handleExecIos(payload);
      case "snapshot": return handleSnapshot();
      case "inspect": return handleInspect(payload);
      case "hardwareInfo": return handleHardwareInfo();
      case "hardwareCatalog": return handleHardwareCatalog(payload);
      case "commandLog": return handleCommandLog(payload);
      case "listCanvasRects": return handleListCanvasRects(payload);
      case "getRect": return handleGetRect(payload);
      case "devicesInRect": return handleDevicesInRect(payload);
      default: return { ok: false, error: "Unknown command: " + payload.type };
    }
  } catch (e) {
    dprint("[Runtime] Error: " + String(e));
    return { ok: false, error: String(e), stack: String(e.stack || "") };
  }
})(payload, ipc, dprint);
